{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://github.com/ryanriley/mobility-tracker/schema/program.schema.json",
  "title": "Training Program",
  "description": "Schema for defining a training program. Programs contain sessions, exercises, weekly schedule templates, progression phases, optional skill goals, benchmarks, and a long-term roadmap.",
  "type": "object",
  "required": ["meta", "sessions", "weekTemplates", "progressions"],
  "additionalProperties": false,
  "properties": {

    "meta": {
      "type": "object",
      "description": "Program metadata.",
      "required": ["version", "title"],
      "additionalProperties": false,
      "properties": {
        "version": {
          "type": "string",
          "description": "Schema version (semver).",
          "pattern": "^\\d+\\.\\d+\\.\\d+$"
        },
        "title": {
          "type": "string",
          "description": "Program title displayed in the app."
        },
        "subtitle": {
          "type": "string"
        },
        "description": {
          "type": "string",
          "description": "Brief description of the program's purpose and scope."
        },
        "author": {
          "type": "string"
        },
        "durationWeeks": {
          "type": "integer",
          "minimum": 0,
          "description": "Total program duration in weeks. 0 = ongoing/indefinite."
        },
        "tags": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Searchable tags (e.g., 'mobility', 'strength', 'calisthenics')."
        }
      }
    },

    "sessions": {
      "type": "array",
      "description": "All sessions in the program. A session is a named group of exercises done together.",
      "items": { "$ref": "#/$defs/session" },
      "minItems": 1
    },

    "weekTemplates": {
      "type": "array",
      "description": "Weekly schedule templates. Users select one template to follow.",
      "items": { "$ref": "#/$defs/weekTemplate" },
      "minItems": 1
    },

    "progressions": {
      "type": "array",
      "description": "Progression phases within the program (e.g., Foundation, Build, Load). Coaching notes adjust per phase.",
      "items": { "$ref": "#/$defs/progression" }
    },

    "roadmap": {
      "type": "array",
      "description": "Optional long-term roadmap phases beyond the core program (e.g., Skill Acquisition, Refinement). Each phase may span many weeks and gate on benchmarks.",
      "items": { "$ref": "#/$defs/roadmapPhase" }
    },

    "skills": {
      "type": "array",
      "description": "Optional long-term skill goals tracked across the roadmap (e.g., Muscle Up, Pistol Squat).",
      "items": { "$ref": "#/$defs/skill" }
    },

    "benchmarks": {
      "type": "array",
      "description": "Optional measurable assessments for tracking progress. Can serve as gate tests between roadmap phases.",
      "items": { "$ref": "#/$defs/benchmark" }
    },

    "foundations": {
      "type": "array",
      "description": "Optional foundational protocols (breathing, bracing, warmup rituals) that apply across the program.",
      "items": { "$ref": "#/$defs/foundation" }
    },

    "theme": {
      "$ref": "#/$defs/theme",
      "description": "Optional color theme for the program."
    }
  },

  "$defs": {

    "session": {
      "type": "object",
      "required": ["id", "title", "exercises"],
      "additionalProperties": false,
      "properties": {
        "id": {
          "type": "string",
          "description": "Unique identifier for the session within this program."
        },
        "title": { "type": "string" },
        "subtitle": { "type": "string" },
        "description": {
          "type": "string",
          "description": "Coaching context explaining why this session exists and what it targets."
        },
        "isDaily": {
          "type": "boolean",
          "default": false,
          "description": "If true, this session resets daily (never reflowed when missed, just dropped and regenerated)."
        },
        "sortOrder": {
          "type": "integer",
          "description": "Display order in the program view."
        },
        "color": {
          "type": "string",
          "description": "Optional CSS color string for theming this session (e.g., 'rgb(96, 165, 224)')."
        },
        "exercises": {
          "type": "array",
          "items": { "$ref": "#/$defs/exercise" },
          "minItems": 1
        }
      }
    },

    "exercise": {
      "type": "object",
      "required": ["id", "name", "sets"],
      "additionalProperties": false,
      "properties": {
        "id": {
          "type": "string",
          "description": "Unique identifier for the exercise within this program."
        },
        "name": { "type": "string" },
        "sets": {
          "type": "string",
          "description": "Human-readable set/rep scheme (e.g., '3×8 each side', '2×45 sec')."
        },
        "notes": {
          "type": "string",
          "description": "Coaching notes, cues, and progression tips."
        },
        "videoURL": {
          "type": ["string", "null"],
          "format": "uri",
          "description": "Link to a tutorial video."
        },
        "searchTerms": {
          "type": ["string", "null"],
          "description": "Search keywords for finding tutorial videos."
        },
        "tags": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Tags indicating cross-cutting concerns (e.g., 'core-integration', 'tspine-integration', 'glute-activation'). Exercises tagged this way originate from a foundational session but appear in other sessions."
        },
        "progressionByPhase": {
          "type": "object",
          "description": "Optional per-phase overrides for sets, notes, or cues. Keys are progression phase names.",
          "additionalProperties": {
            "type": "object",
            "properties": {
              "sets": { "type": "string" },
              "notes": { "type": "string" }
            }
          }
        }
      }
    },

    "weekTemplate": {
      "type": "object",
      "required": ["id", "name", "days"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "name": {
          "type": "string",
          "description": "Display name (e.g., '5-Day (Recommended)')."
        },
        "description": { "type": "string" },
        "sortOrder": { "type": "integer" },
        "days": {
          "type": "array",
          "description": "Seven entries, one per day of the week (Monday=index 0).",
          "items": { "$ref": "#/$defs/daySlot" },
          "minItems": 7,
          "maxItems": 7
        }
      }
    },

    "daySlot": {
      "type": "object",
      "required": ["dayOfWeek"],
      "additionalProperties": false,
      "properties": {
        "dayOfWeek": {
          "type": "integer",
          "minimum": 0,
          "maximum": 6,
          "description": "0=Monday, 6=Sunday."
        },
        "sessionIDs": {
          "type": "array",
          "items": { "type": "string" },
          "default": [],
          "description": "References to session IDs scheduled for this day. Empty = rest or user-directed."
        },
        "note": {
          "type": ["string", "null"],
          "description": "Optional coaching note for the day (e.g., 'Strength training — CARs as warmup')."
        }
      }
    },

    "progression": {
      "type": "object",
      "required": ["id", "weekRange", "phaseName"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "weekRange": {
          "type": "string",
          "description": "Human-readable week range (e.g., 'Weeks 1-2')."
        },
        "phaseName": {
          "type": "string",
          "description": "Phase name (e.g., 'Foundation', 'Build', 'Load')."
        },
        "focus": {
          "type": "string",
          "description": "One-line coaching summary for this phase."
        },
        "details": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Specific coaching adjustments and guidance for this phase."
        },
        "weekStart": {
          "type": "integer",
          "minimum": 1,
          "description": "First week number of this phase (for programmatic use)."
        },
        "weekEnd": {
          "type": "integer",
          "minimum": 1,
          "description": "Last week number of this phase."
        },
        "sortOrder": { "type": "integer" }
      }
    },

    "roadmapPhase": {
      "type": "object",
      "required": ["id", "name"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "name": {
          "type": "string",
          "description": "Phase name (e.g., 'Phase 2: Strength Prerequisites')."
        },
        "weeks": {
          "type": "string",
          "description": "Human-readable duration (e.g., 'Weeks 9-20')."
        },
