 1→using System.Text.Json;
 2→using Microsoft.FSharp.Collections;
 3→
 4→// ReSharper disable PossibleMultipleEnumeration
 5→
 6→namespace StarFederation.Datastar;
 7→
 8→internal static class Utilities
 9→{
10→    public static JsonElement? Get(this JsonElement element, string name) =>
11→        element.ValueKind != JsonValueKind.Null && element.ValueKind != JsonValueKind.Undefined && element.TryGetProperty(name, out JsonElement value)
12→            ? value
13→            : null;
14→
15→    public static JsonElement? Get(this JsonElement element, int index) =>
16→        element.ValueKind == JsonValueKind.Null || element.ValueKind == JsonValueKind.Undefined ? null :
17→        index < element.GetArrayLength() ? element[index] : null;
18→
19→    /// <summary>
20→    /// Given a dot-separated path into a JSON structure, will return the JsonElement or null
21→    /// </summary>
22→    /// <param name="jsonElement">the head of the tree</param>
23→    /// <param name="path">dot-separated path</param>
24→    /// <returns>JsonElement if found; null if the path cannot be followed</returns>
25→    public static JsonElement? GetFromPath(this JsonElement jsonElement, string path)
26→    {
27→        JsonElement? GetFromPathCore(JsonElement jElement, IEnumerable<string> pathElements)
28→        {
29→            if (!pathElements.Any())
30→            {
31→                return null;
32→            }
33→
34→            while (true)
35→            {
36→                if (pathElements.Count() == 1)
37→                {
38→                    return jElement.Get(pathElements.First());
39→                }
40→                if (jElement.Get(pathElements.First()) is not { } childElement)
41→                {
42→                    return null;
43→                }
44→                jElement = childElement;
45→                pathElements = pathElements.Skip(1);
46→            }
47→        }
48→        return GetFromPathCore(jsonElement, path.Split('.'));
49→    }
50→
51→    /// <summary>
52→    /// Given a dot-separated path into a JSON structure, will return the value or null
53→    /// </summary>
54→    /// <param name="jsonElement">the head of the tree</param>
55→    /// <param name="path">dot-separated path</param>
56→    /// <param name="jsonElementType">the type to convert the value into</param>
57→    /// <param name="jsonSerializerOptions">options to the serializer</param>
58→    /// <returns>value if found; null if the path cannot be followed</returns>
59→    public static object? GetValueFromPath(this JsonElement jsonElement, string path, Type jsonElementType, JsonSerializerOptions jsonSerializerOptions)
60→    {
61→        JsonElement? childJsonElement = GetFromPath(jsonElement, path);
62→        return childJsonElement?.Deserialize(jsonElementType, jsonSerializerOptions);
63→    }
64→
65→    public static Tuple<TKey, TValue> AsTuple<TKey, TValue>(this KeyValuePair<TKey, TValue> keyValuePair) => new(keyValuePair.Key, keyValuePair.Value);
66→    public static Tuple<TKey, TValue> AsTuple<TKey, TValue>(this (TKey, TValue) keyValuePair) => new(keyValuePair.Item1, keyValuePair.Item2);
67→
68→    public static FSharpList<TType> ToFSharpList<TType>(this IEnumerable<TType> @this)
69→        => @this.Aggregate(FSharpList<TType>.Empty, (current, item) => new FSharpList<TType>(item, current));
70→}

 1→namespace StarFederation.Datastar;
 2→
 3→public enum ElementPatchMode
 4→{
 5→    /// Morphs the element into the existing element.
 6→    Outer,
 7→    /// Replaces the inner HTML of the existing element.
 8→    Inner,
 9→    /// Removes the existing element.
10→    Remove,
11→    /// Replaces the existing element with the new element.
12→    Replace,
13→    /// Prepends the element inside to the existing element.
14→    Prepend,
15→    /// Appends the element inside the existing element.
16→    Append,
17→    /// Inserts the element before the existing element.
18→    Before,
19→    /// Inserts the element after the existing element.
20→    After
