72→    public static string EnumToString(PatchElementNamespace enumValue) => enumValue switch
73→    {
74→        PatchElementNamespace.Html => "html",
75→        PatchElementNamespace.Svg => "svg",
76→        PatchElementNamespace.MathMl => "mathml",
77→        _ => throw new NotImplementedException($"PatchElementNamespace.{enumValue}")
