 1→using System.Diagnostics;
 2→using System.Text.Json.Serialization;
 3→using StarFederation.Datastar.DependencyInjection;
 4→
 5→namespace HelloWorld;
 6→
 7→public static class Program
 8→{
 9→    public static void Main(string[] args)
10→    {
11→        WebApplicationBuilder builder = WebApplication.CreateBuilder(args);
12→        builder.Services.AddDatastar();
13→
14→        WebApplication app = builder.Build();
15→        app.UseStaticFiles();
16→
17→        app.MapGet("/stream-element-patches", async (IDatastarService datastarService) =>
18→        {
19→            const string message = "Hello, Elements!";
20→            Signals? mySignals = await datastarService.ReadSignalsAsync<Signals>();
21→            Debug.Assert(mySignals != null, nameof(mySignals) + " != null");
22→
23→            await datastarService.PatchSignalsAsync(new { ShowPatchElementMessage = true });
24→
25→            for (var index = 1; index < message.Length; ++index)
26→            {
27→                await datastarService.PatchElementsAsync($"""<div id="message">{message[..index]}</div>""");
28→                await Task.Delay(TimeSpan.FromMilliseconds(mySignals.Delay.GetValueOrDefault(0)));
29→            }
30→
31→            await datastarService.PatchElementsAsync($"""<div id="message">{message}</div>""");
32→        });
33→
34→        app.MapGet("/stream-signal-patches", async (IDatastarService datastarService) =>
35→        {
36→            const string message = "Hello, Signals!";
37→            Signals? mySignals = await datastarService.ReadSignalsAsync<Signals>();
38→            Debug.Assert(mySignals != null, nameof(mySignals) + " != null");
39→
40→            await datastarService.PatchSignalsAsync(new { ShowPatchElementMessage = false });
41→
42→            for (var index = 1; index < message.Length; ++index)
43→            {
44→                await datastarService.PatchSignalsAsync(new { SignalsMessage = message[..index] });
45→                await Task.Delay(TimeSpan.FromMilliseconds(mySignals.Delay.GetValueOrDefault(0)));
46→            }
47→
48→            await datastarService.PatchSignalsAsync(new { SignalsMessage = message });
49→        });
50→
51→        app.MapGet("/execute-script", (IDatastarService datastarService) =>
52→            datastarService.ExecuteScriptAsync("alert('Hello! from the server 🚀')"));
53→
54→        app.Run();
55→    }
56→
57→    public record Signals
58→    {
59→        [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
60→        public float? Delay { get; set; } = null;
61→    }
62→}

