531→
532→export function patchElements(html: string, opts?: PatchOptions): string {
533→  let lines = `event: datastar-patch-elements\n`;
534→  if (opts?.selector) lines += `data: selector ${opts.selector}\n`;
535→  if (opts?.mode) lines += `data: mode ${opts.mode}\n`;
536→  if (opts?.useViewTransition) lines += `data: useViewTransition true\n`;
537→  lines += `data: elements ${html}\n\n`;
538→  return lines;
539→}
