591→```typescript
592→export interface AuthResult {
593→  userId: string;
594→  email: string;
595→}
596→
597→export function getAuthenticatedUser(request: Request): AuthResult | null {
598→  // Cloudflare Access sets this header with the JWT
599→  const jwt = request.headers.get("cf-access-jwt-assertion");

600→  if (!jwt) return null;
601→
602→  try {
603→    // Decode the JWT payload (Cloudflare Access has already validated it at the edge)
604→    const parts = jwt.split(".");
605→    if (parts.length !== 3) return null;
606→    const payload = JSON.parse(atob(parts[1]));
607→    const email = payload.email;
608→    if (!email) return null;
609→    return { userId: email, email };
610→  } catch {
611→    return null;
612→  }
613→}
614→
615→export function requireAuth(request: Request): AuthResult {
616→  const user = getAuthenticatedUser(request);
617→  if (!user) {
618→    throw new Response("Unauthorized", { status: 403 });
619→  }
620→  return user;
621→}
622→```
