882→Create `src/domain/reflow.ts`:
883→
884→```typescript
885→import type { QueueItemRow, WeekTemplate, Session } from "~/types";
886→
887→export interface UpcomingItem {
888→  type: "session" | "spacer";
889→  sessionId?: string;
890→  title: string;
891→  exerciseCount?: number;
892→  color?: string;
893→}
894→
895→export function computeUpcoming(
896→  pendingItems: QueueItemRow[],
897→  template: WeekTemplate,
898→  sessions: Session[],
899→  maxSessions: number
900→): UpcomingItem[] {
901→  const sessionMap = new Map(sessions.map((s) => [s.id, s]));
902→
903→  // Build the template rhythm: which day indices are spacers vs sessions
904→  const templateRhythm: Array<{ type: "session" | "spacer"; sessionId?: string }> = [];
905→  for (const day of template.days) {
906→    const mainIds = (day.sessionIDs ?? []).filter((sid) => {
907→      const s = sessionMap.get(sid);
908→      return s && !s.isDaily;
909→    });
910→    if (mainIds.length === 0 && (day.sessionIDs ?? []).length > 0) {
911→      // Has sessions but all are daily → spacer day
912→      templateRhythm.push({ type: "spacer" });
913→    } else if (mainIds.length > 0) {
914→      for (const sid of mainIds) {
915→        templateRhythm.push({ type: "session", sessionId: sid });
916→      }
917→    }
918→    // Empty sessionIDs (rest days) are skipped — they don't appear in "coming up"
919→  }
920→
921→  // Walk the pending items, interleave spacers from the template rhythm
922→  const result: UpcomingItem[] = [];
923→  let rhythmIndex = 0;
924→  let sessionCount = 0;
925→
926→  // Find where in the rhythm the first pending item falls
927→  const firstPending = pendingItems[0];
928→  if (firstPending) {
929→    // Find this session's position in the rhythm cycle
930→    for (let i = 0; i < templateRhythm.length; i++) {
931→      if (templateRhythm[i].sessionId === firstPending.session_id) {
932→        rhythmIndex = i;
933→        break;
934→      }
935→    }
936→  }
937→
938→  let pendingIdx = 0;
939→  while (sessionCount < maxSessions && pendingIdx < pendingItems.length) {
940→    const rhythmSlot = templateRhythm[rhythmIndex % templateRhythm.length];
941→
942→    if (rhythmSlot.type === "spacer") {
943→      result.push({ type: "spacer", title: "CARs only" });
944→    } else {
945→      const item = pendingItems[pendingIdx];
946→      const session = sessionMap.get(item.session_id);
947→      result.push({
948→        type: "session",
949→        sessionId: item.session_id,
950→        title: session?.title ?? item.session_id,
951→        exerciseCount: session?.exercises.length,
952→        color: session?.color,
953→      });
954→      pendingIdx++;
955→      sessionCount++;
956→    }
957→
958→    rhythmIndex++;
959→  }
960→
961→  return result;
962→}
963→```
