1247→  private async request<T>(path: string, init?: RequestInit): Promise<T> {
1248→    const url = `${this.baseUrl}${path}`;
1249→    const res = await fetch(url, {
1250→      ...init,
1251→      headers: {
1252→        "api-key": this.apiKey,
1253→        "accept": "application/json",
1254→        "content-type": "application/json",
1255→        ...(init?.headers ?? {}),
1256→      },
1257→    });
1258→
1259→    if (res.status === 429) {
1260→      // Rate limited — caller should handle backoff
1261→      throw new Error("RATE_LIMITED");
1262→    }
1263→
1264→    if (!res.ok) {
1265→      throw new Error(`Hevy API error: ${res.status} ${res.statusText}`);
