1425→
1426→```typescript
1427→import type { Session, ExerciseMappingRow, QueueItemRow } from "~/types";
1428→import type { HevyRoutineExercise, HevyWorkout, HevyExerciseTemplate, HevySet } from "~/hevy/client";
1429→
1430→interface RoutinePayload {
1431→  title: string;
1432→  exercises: HevyRoutineExercise[];
1433→  unmapped: string[];
1434→}
1435→
1436→export function buildRoutinePayload(
1437→  session: Session,
1438→  mappings: ExerciseMappingRow[]
1439→): RoutinePayload {
1440→  const mappingMap = new Map(mappings.map((m) => [m.program_exercise_name, m.hevy_exercise_id]));
1441→  const exercises: HevyRoutineExercise[] = [];
1442→  const unmapped: string[] = [];
1443→
1444→  for (const ex of session.exercises) {
1445→    const hevyId = mappingMap.get(ex.name);
1446→    if (!hevyId) {
1447→      unmapped.push(ex.name);
1448→      continue;
1449→    }
1450→    // Parse sets string into Hevy set objects
1451→    const sets = parseSetsToHevy(ex.sets);
1452→    exercises.push({
1453→      exercise_template_id: hevyId,
1454→      sets,
1455→      notes: ex.notes ?? undefined,
1456→    });
1457→  }
1458→
1459→  return { title: session.title, exercises, unmapped };
1460→}
1461→
1462→function parseSetsToHevy(setsStr: string): HevySet[] {
1463→  // Parse patterns like "3×8", "3×30 sec", "2×45 sec", "3×8 each side"
1464→  const match = setsStr.match(/(\d+)[×x](\d+)/);
1465→  if (!match) {
1466→    return [{ type: "normal", reps: 1 }];
1467→  }
1468→
1469→  const setCount = parseInt(match[1]);
1470→  const repOrDuration = parseInt(match[2]);
1471→  const isDuration = /sec|min/i.test(setsStr);
1472→
1473→  return Array.from({ length: setCount }, () => ({
1474→    type: "normal" as const,
1475→    ...(isDuration ? { duration_seconds: repOrDuration } : { reps: repOrDuration }),
1476→  }));
1477→}
1478→
1479→interface CompletionMatch {
1480→  queueItemId: number;
1481→  workoutId: string;
1482→}
1483→
1484→export function matchCompletions(
1485→  items: QueueItemRow[],
1486→  workouts: HevyWorkout[],
1487→  getRoutineIdForWorkout: (workout: HevyWorkout) => string | null
1488→): CompletionMatch[] {
1489→  const matches: CompletionMatch[] = [];
1490→  const routineToItem = new Map<string, QueueItemRow>();
1491→
1492→  for (const item of items) {
1493→    if (item.status === "pending" && item.hevy_routine_id) {
1494→      routineToItem.set(item.hevy_routine_id, item);
1495→    }
1496→  }
1497→
1498→  for (const workout of workouts) {
1499→    const routineId = getRoutineIdForWorkout(workout);
1500→    if (!routineId) continue;
1501→    const item = routineToItem.get(routineId);
1502→    if (item) {
1503→      matches.push({ queueItemId: item.id, workoutId: workout.id });
1504→    }
1505→  }
1506→
1507→  return matches;
1508→}
1509→
1510→export function autoMatchExercises(
1511→  programNames: string[],
1512→  hevyTemplates: HevyExerciseTemplate[]
1513→): Map<string, string> {
1514→  const matches = new Map<string, string>();
1515→
1516→  const normalize = (s: string) =>
1517→    s.toLowerCase().replace(/[^a-z0-9]/g, "").replace(/s$/, "");
1518→
1519→  const hevyByNorm = new Map<string, HevyExerciseTemplate>();
1520→  for (const t of hevyTemplates) {
1521→    hevyByNorm.set(normalize(t.title), t);
1522→  }
1523→
1524→  for (const name of programNames) {
1525→    const norm = normalize(name);
1526→    const match = hevyByNorm.get(norm);
1527→    if (match) {
1528→      matches.set(name, match.id);
1529→    } else {
1530→      // Try partial match — check if normalized name is contained
1531→      for (const [hevyNorm, template] of hevyByNorm) {
1532→        if (hevyNorm.includes(norm) || norm.includes(hevyNorm)) {
1533→          matches.set(name, template.id);
1534→          break;
1535→        }
1536→      }
1537→    }
1538→  }
1539→
1540→  return matches;
1541→}
1542→```
