## Task 2: Program Types & Bundled JSON

**Files:**
- Create: `src/types.ts`, `programs/mobility-joint-restoration.json`
- Reference: `schema/program.schema.json`

- [ ] **Step 1: Define TypeScript types**

Create `src/types.ts`. These types mirror `schema/program.schema.json`:

```typescript
// Program JSON types (read-only, loaded from bundled JSON)

export interface Program {
  meta: ProgramMeta;
  sessions: Session[];
  weekTemplates: WeekTemplate[];
  progressions: Progression[];
  roadmap?: RoadmapPhase[];
  skills?: Skill[];
  benchmarks?: Benchmark[];
  foundations?: Foundation[];
  theme?: Theme;
}

export interface ProgramMeta {
  version: string;
  title: string;
  subtitle?: string;
  description?: string;
  author?: string;
  durationWeeks?: number;
  tags?: string[];
}

export interface Session {
  id: string;
  title: string;
  subtitle?: string;
  description?: string;
  isDaily?: boolean;
  sortOrder?: number;
  color?: string;
  exercises: Exercise[];
}

export interface Exercise {
  id: string;
  name: string;
  sets: string;
  notes?: string;
  videoURL?: string | null;
