526→export interface PatchOptions {
527→  selector?: string;
528→  mode?: "outer" | "inner" | "append" | "prepend" | "before" | "after" | "remove";
529→  useViewTransition?: boolean;
530→}
531→
532→export function patchElements(html: string, opts?: PatchOptions): string {
533→  let lines = `event: datastar-patch-elements\n`;
534→  if (opts?.selector) lines += `data: selector ${opts.selector}\n`;
535→  if (opts?.mode) lines += `data: mode ${opts.mode}\n`;
536→  if (opts?.useViewTransition) lines += `data: useViewTransition true\n`;
537→  lines += `data: elements ${html}\n\n`;
538→  return lines;
539→}
540→
541→export function patchSignals(signals: Record<string, unknown>): string {
542→  return `event: datastar-patch-signals\ndata: signals ${JSON.stringify(signals)}\n\n`;
543→}
544→
545→export function mergeFragments(fragments: string[]): string {
546→  return fragments.join("");
