548→
549→export function sseResponse(body: string): Response {
550→  return new Response(body, {
551→    headers: {
552→      "content-type": "text/event-stream",
553→      "cache-control": "no-cache",
554→      "connection": "keep-alive",
555→    },
556→  });
557→}
558→
559→export function isSSERequest(request: Request): boolean {
560→  const accept = request.headers.get("accept") || "";
561→  return accept.includes("text/event-stream");
