737→```typescript
738→import type { WeekTemplate, Session, QueueItemRow } from "~/types";
739→
740→interface PlaylistItem {
741→  session_id: string;
742→  position: number;
743→}
744→
745→export function generatePlaylist(
746→  template: WeekTemplate,
747→  sessions: Session[],
748→  weeks: number
749→): PlaylistItem[] {
750→  const sessionMap = new Map(sessions.map((s) => [s.id, s]));
751→  const mainSessionOrder: string[] = [];
752→
753→  // Walk through the week template, extract non-daily session IDs in order
754→  for (const day of template.days) {
755→    if (!day.sessionIDs) continue;
756→    for (const sid of day.sessionIDs) {
757→      const session = sessionMap.get(sid);
758→      if (session && !session.isDaily) {
759→        mainSessionOrder.push(sid);
760→      }
761→    }
762→  }
763→
764→  // Repeat for the requested number of weeks
765→  const playlist: PlaylistItem[] = [];
766→  for (let week = 0; week < weeks; week++) {
767→    for (const sid of mainSessionOrder) {
768→      playlist.push({
769→        session_id: sid,
770→        position: playlist.length,
771→      });
772→    }
773→  }
774→
775→  return playlist;
776→}
777→
778→export function getNextSession(items: QueueItemRow[]): QueueItemRow | null {
779→  const sorted = [...items].sort((a, b) => a.position - b.position);
780→  return sorted.find((item) => item.status === "pending") ?? null;
781→}
782→
783→export function getCompletedSessions(items: QueueItemRow[], today: string): QueueItemRow[] {
784→  return items
785→    .filter((item) => item.status === "completed" && item.completed_date === today)
786→    .sort((a, b) => a.position - b.position);
787→}
788→```
