883→
884→```typescript
885→import type { QueueItemRow, WeekTemplate, Session } from "~/types";
886→
887→/**
888→ * Evaluate reflow on page load. The queue is a conveyor belt —
889→ * main sessions never drop. This function is pure: it returns
890→ * the updated statuses without touching D1.
891→ *
892→ * Reflow rules (from spec):
893→ * 1. Missed main session, next day CARs-only → absorb spacer, session slides
894→ * 2. Missed main session, next day has session → conveyor belt shift
895→ * 3. Missed CARs-only day, next has session → drop spacer, session moves up
896→ *
897→ * Since the queue only contains main sessions (CARs are ambient),
898→ * the conveyor belt is automatic: the first pending item IS the next
899→ * session, regardless of how many days passed. No items need moving.
900→ * The "reflow" is inherent in the playlist model.
901→ */
902→export function evaluateReflow(
903→  _items: QueueItemRow[],
904→  _today: string
905→): void {
906→  // The conveyor belt model means reflow is a no-op on the queue itself.
907→  // The first pending item is always "today's session" regardless of
908→  // how many days were missed. Spacer interpolation happens at display
909→  // time in computeUpcoming(). No queue mutations needed.
910→}
911→
912→export interface UpcomingItem {
913→  type: "session" | "spacer";
914→  sessionId?: string;
915→  title: string;
916→  exerciseCount?: number;
917→  color?: string;
918→}
919→
920→export function computeUpcoming(
921→  pendingItems: QueueItemRow[],
922→  template: WeekTemplate,
923→  sessions: Session[],
924→  maxSessions: number
925→): UpcomingItem[] {
926→  const sessionMap = new Map(sessions.map((s) => [s.id, s]));
927→
928→  // Build the template rhythm: which day indices are spacers vs sessions
929→  const templateRhythm: Array<{ type: "session" | "spacer"; sessionId?: string }> = [];
930→  for (const day of template.days) {
931→    const mainIds = (day.sessionIDs ?? []).filter((sid) => {
932→      const s = sessionMap.get(sid);
933→      return s && !s.isDaily;
934→    });
935→    if (mainIds.length === 0 && (day.sessionIDs ?? []).length > 0) {
936→      // Has sessions but all are daily → spacer day
937→      templateRhythm.push({ type: "spacer" });
938→    } else if (mainIds.length > 0) {
939→      for (const sid of mainIds) {
940→        templateRhythm.push({ type: "session", sessionId: sid });
941→      }
942→    }
943→    // Empty sessionIDs (rest days) are skipped — they don't appear in "coming up"
944→  }
945→
946→  // Walk the pending items, interleave spacers from the template rhythm
947→  const result: UpcomingItem[] = [];
948→  let rhythmIndex = 0;
949→  let sessionCount = 0;
950→
951→  // Find where in the rhythm the first pending item falls
952→  const firstPending = pendingItems[0];
953→  if (firstPending) {
954→    // Find this session's position in the rhythm cycle
955→    for (let i = 0; i < templateRhythm.length; i++) {
956→      if (templateRhythm[i].sessionId === firstPending.session_id) {
957→        rhythmIndex = i;
958→        break;
959→      }
960→    }
961→  }
962→
963→  let pendingIdx = 0;
964→  while (sessionCount < maxSessions && pendingIdx < pendingItems.length) {
965→    const rhythmSlot = templateRhythm[rhythmIndex % templateRhythm.length];
966→
967→    if (rhythmSlot.type === "spacer") {
968→      result.push({ type: "spacer", title: "CARs only" });
969→    } else {
970→      const item = pendingItems[pendingIdx];
971→      const session = sessionMap.get(item.session_id);
972→      result.push({
973→        type: "session",
974→        sessionId: item.session_id,
975→        title: session?.title ?? item.session_id,
976→        exerciseCount: session?.exercises.length,
977→        color: session?.color,
978→      });
979→      pendingIdx++;
980→      sessionCount++;
981→    }
982→
983→    rhythmIndex++;
984→  }
985→
986→  return result;
987→}
988→```
