1451→```typescript
1452→import type { Session, ExerciseMappingRow, QueueItemRow } from "~/types";
1453→import type { HevyRoutineExercise, HevyWorkout, HevyExerciseTemplate, HevySet } from "~/hevy/client";
1454→
1455→interface RoutinePayload {
1456→  title: string;
1457→  exercises: HevyRoutineExercise[];
1458→  unmapped: string[];
1459→}
1460→
1461→export function buildRoutinePayload(
1462→  session: Session,
1463→  mappings: ExerciseMappingRow[]
1464→): RoutinePayload {
1465→  const mappingMap = new Map(mappings.map((m) => [m.program_exercise_name, m.hevy_exercise_id]));
1466→  const exercises: HevyRoutineExercise[] = [];
1467→  const unmapped: string[] = [];
1468→
1469→  for (const ex of session.exercises) {
1470→    const hevyId = mappingMap.get(ex.name);
1471→    if (!hevyId) {
1472→      unmapped.push(ex.name);
1473→      continue;
1474→    }
1475→    // Parse sets string into Hevy set objects
1476→    const sets = parseSetsToHevy(ex.sets);
1477→    exercises.push({
1478→      exercise_template_id: hevyId,
1479→      sets,
1480→      notes: ex.notes ?? undefined,
1481→    });
1482→  }
1483→
1484→  return { title: session.title, exercises, unmapped };
1485→}
1486→
1487→function parseSetsToHevy(setsStr: string): HevySet[] {
1488→  // Parse patterns like "3×8", "3×30 sec", "2×45 sec", "3×8 each side"
1489→  const match = setsStr.match(/(\d+)[×x](\d+)/);
1490→  if (!match) {
1491→    return [{ type: "normal", reps: 1 }];
1492→  }
1493→
1494→  const setCount = parseInt(match[1]);
1495→  const repOrDuration = parseInt(match[2]);
1496→  const isDuration = /sec|min/i.test(setsStr);
1497→
1498→  return Array.from({ length: setCount }, () => ({
1499→    type: "normal" as const,
1500→    ...(isDuration ? { duration_seconds: repOrDuration } : { reps: repOrDuration }),
1501→  }));
1502→}
1503→
1504→interface CompletionMatch {
1505→  queueItemId: number;
1506→  workoutId: string;
1507→}
1508→
1509→export function matchCompletions(
1510→  items: QueueItemRow[],
1511→  workouts: HevyWorkout[],
1512→  getRoutineIdForWorkout: (workout: HevyWorkout) => string | null
1513→): CompletionMatch[] {
1514→  const matches: CompletionMatch[] = [];
1515→  const routineToItem = new Map<string, QueueItemRow>();
1516→
1517→  for (const item of items) {
1518→    if (item.status === "pending" && item.hevy_routine_id) {
1519→      routineToItem.set(item.hevy_routine_id, item);
1520→    }
1521→  }
1522→
1523→  for (const workout of workouts) {
1524→    const routineId = getRoutineIdForWorkout(workout);
1525→    if (!routineId) continue;
1526→    const item = routineToItem.get(routineId);
1527→    if (item) {
1528→      matches.push({ queueItemId: item.id, workoutId: workout.id });
1529→    }
1530→  }
1531→
1532→  return matches;
1533→}
1534→
1535→export function autoMatchExercises(
1536→  programNames: string[],
1537→  hevyTemplates: HevyExerciseTemplate[]
1538→): Map<string, string> {
1539→  const matches = new Map<string, string>();
1540→
1541→  const normalize = (s: string) =>
1542→    s.toLowerCase().replace(/[^a-z0-9]/g, "").replace(/s$/, "");
1543→
1544→  const hevyByNorm = new Map<string, HevyExerciseTemplate>();
1545→  for (const t of hevyTemplates) {
1546→    hevyByNorm.set(normalize(t.title), t);
1547→  }
1548→
1549→  for (const name of programNames) {
1550→    const norm = normalize(name);
1551→    const match = hevyByNorm.get(norm);
1552→    if (match) {
1553→      matches.set(name, match.id);
1554→    } else {
1555→      // Try partial match — check if normalized name is contained
1556→      for (const [hevyNorm, template] of hevyByNorm) {
1557→        if (hevyNorm.includes(norm) || norm.includes(hevyNorm)) {
1558→          matches.set(name, template.id);
1559→          break;
1560→        }
1561→      }
1562→    }
1563→  }
1564→
1565→  return matches;
1566→}
1567→```
