function hexWithAlpha(cssColor: string, alpha: number): string {
  // Handle "rgb(r, g, b)" format
  const match = cssColor.match(/(\d+)\s*,\s*(\d+)\s*,\s*(\d+)/);
  if (match) return `rgba(${match[1]},${match[2]},${match[3]},${alpha})`;
  return cssColor;
}
