): Promise<void> {
  await db
    .prepare(
      "UPDATE queue_items SET status = 'completed', completed_date = ?, hevy_workout_id = ? WHERE id = ?"
    )
    .bind(completedDate, hevyWorkoutId ?? null, itemId)
    .run();
}

export async function updateQueueItemHevyRoutineId(
  db: D1Database,
